// The robot can only ARRIVE at (i,j) from directly ABOVE (i-1,j) or directly to the LEFT (i,j-1)
// So the number of ways to reach (i,j) is the SUM of the ways to reach each of those

// dp[i][j] = dp[i-1][j] + dp[i][j-1]

#include <iostream>
#include <vector>

using namespace std;

int uniquePaths(int m, int n)
{
    vector<vector<int>> dp(m, vector<int>(n));

    for (int i = 0; i < m; i++)
    {
        for (int j = 0; j < n; j++)
        {
            if (i == 0 || j == 0)
            {
                dp[i][j] = 1; // top row or left column — exactly one way
            }
            else
            {
                dp[i][j] = dp[i - 1][j] + dp[i][j - 1];
            }
        }
    }

    return dp[m - 1][n - 1];
}

int main()
{
    cout << uniquePaths(3, 3) << endl;

    return 0;
}

