#include <algorithm>

using namespace std;

int minPathSum(vector<vector<int>>& grid)
{
    int rows = grid.size(), cols = grid[0].size();
    vector<int> row(cols);

    row[0] = grid[0][0];
    for (int j = 1; j < cols; j++) row[j] = row[j - 1] + grid[0][j];

    for (int i = 1; i < rows; i++)
    {
        row[0] += grid[i][0]; // only one way in: straight down the left edge
        for (int j = 1; j < cols; j++)
            row[j] = grid[i][j] + min(row[j], row[j - 1]); // row[j] is still "from above"; row[j-1] is already this row's "from left"
    }

    return row[cols - 1];
}

int main()
{
    vector<vector<int>> grid = {
        {1, 3, 1},
        {1, 5, 1},
        {4, 2, 1}
    };

    cout << minPathSum(grid);

    return 0;
}

