#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

int minFallingPathSum(vector<vector<int>>& matrix)
{
    int n = matrix.size();
    vector<vector<int>> dp = matrix;

    for (int row = n - 2; row >= 0; row--)
        for (int j = 0; j < n; j++)
        {
            int best = dp[row + 1][j];
            if (j > 0) best = min(best, dp[row + 1][j - 1]);
            if (j < n - 1) best = min(best, dp[row + 1][j + 1]);
            dp[row][j] = matrix[row][j] + best;
        }

    int result = INT_MAX;
    for (int j = 0; j < n; j++) result = min(result, dp[0][j]);
    return result;
}

int main()
{
    vector<vector<int>> matrix = {{2, 1, 3}, {6, 5, 4}, {7, 8, 9}};
    cout << minFallingPathSum(matrix);

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

int minFallingPathSum(vector<vector<int>>& matrix)
{
    int n = matrix.size();
    vector<int> dp = matrix[n - 1];

    for (int row = n - 2; row >= 0; row--)
    {
        vector<int> newDp(n);
        for (int j = 0; j < n; j++)
        {
            int best = dp[j];
            if (j > 0) best = min(best, dp[j - 1]);
            if (j < n - 1) best = min(best, dp[j + 1]);
            newDp[j] = matrix[row][j] + best;
        }
        dp = newDp;
    }

    int result = INT_MAX;
    for (int val : dp) result = min(result, val);
    return result;
}

int main()
{
    vector<vector<int>> matrix = {{2, 1, 3}, {6, 5, 4}, {7, 8, 9}};
    cout << minFallingPathSum(matrix);

    return 0;
}

